struct AtomicCompoundSnapshot {
    int afterAddition;
    int afterMultiplication;
    int afterBitwiseAnd;
    int afterShift;
    int postIncrementReturn;
    int finalValue;
    int calcEvaluations;
};

/**
 * Function: Demonstrate atomic compound assignments on a reactive counter.
 *
 * @return AtomicCompoundSnapshot Snapshot with values after each compound operation.
 */
inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    using namespace reaction;

    // 1. Create reactive variable initialized to 0
    auto reactiveVar = var(0);

    // 2. Create counter to track calculation evaluations
    auto calcCounter = var(0);

    // 3. Create calculation to track value
    auto trackerCalc = calc([&]() {
        calcCounter += 1;  // Increment counter each time calculation runs
        return reactiveVar();
    });

    // Initialize the calculation by getting the value
    trackerCalc.get();

    // 4. Apply atomic addition: += 5
    reactiveVar += 5;

    // 5. Get value after addition
    int afterAdd = reactiveVar.get();

    // 6. Apply atomic multiplication: *= 2
    reactiveVar *= 2;

    // 7. Get value after multiplication
    int afterMult = reactiveVar.get();

    // 8. Apply atomic bitwise AND: &= 0x0F
    reactiveVar &= 0x0F;

    // 9. Get value after bitwise AND
    int afterAnd = reactiveVar.get();

    // 10. Apply atomic left shift: <<= 2
    reactiveVar <<= 2;

    // 11. Get value after shift
    int afterShiftVal = reactiveVar.get();

    // 12. Apply post-increment: ++
    int postIncReturn = reactiveVar++;

    // 13. Get final value
    int finalVal = reactiveVar.get();

    // 14. Return atomic compound snapshot
    return AtomicCompoundSnapshot{
        afterAdd,
        afterMult,
        afterAnd,
        afterShiftVal,
        postIncReturn,
        finalVal,
        calcCounter.get()  // Number of evaluations
    };
}

